import { takeEvery, call, put, all, select } from 'redux-saga/effects';
import {
  DATA_LOAD_REQUESTED,
  DATA_LOADED,
  API_ERRORED,
  FILTER_BY_NAME_REQUESTED,
  FILTER_BY_COUNTRY_REQUESTED,
  DATA_FILTERED,
  USER_DETAIL_REQUESTED,
  DETAIL_MODAL_TOGGLE,
  BATCH_SIZE,
  TRUNCATE_DATA_LOAD_REQUESTED,
  DATA_TRUNCATED,
  DATA_APPEND_REQUESTED,
  DATA_APPEND,
  DATA_MERGE_REQUESTED,
  DATA_MERGED
} from '../constants/action-types';

export default function* watcherSaga() {
  yield all([
    takeEvery(DATA_LOAD_REQUESTED, workerLoadData),
    takeEvery(DATA_APPEND_REQUESTED, workerAppendData),
    takeEvery(DATA_MERGE_REQUESTED, workerMergeData),
    takeEvery(FILTER_BY_NAME_REQUESTED, workerFilterNameData),
    takeEvery(FILTER_BY_COUNTRY_REQUESTED, workerFilterCountryData),
    takeEvery(USER_DETAIL_REQUESTED, workerUserDetail),
    takeEvery(TRUNCATE_DATA_LOAD_REQUESTED, workerTruncateData)
  ]);
}

export const getAPIFilter = state => state.apiCountryFilter;
export const getNextUsersBatch = state => state.nextUsersBatch;

function* workerFilterNameData() {
  yield put({ type: DATA_FILTERED });
}

function* workerFilterCountryData() {
  yield put({ type: DATA_FILTERED });
}

function* workerTruncateData() {
  yield put({ type: DATA_TRUNCATED });
}

function* workerUserDetail() {
  yield put({ type: DETAIL_MODAL_TOGGLE });
}

function* workerLoadData() {
  try {
    const apiFilter = yield select(getAPIFilter);
    const payload = yield call(getData, apiFilter);
    yield put({ type: DATA_LOADED, payload: payload.results });
  } catch (e) {
    yield put({ type: API_ERRORED, payload: e });
  }
}

function* workerAppendData() {
  try {
    const apiFilter = yield select(getAPIFilter);
    const payload = yield call(getData, apiFilter);
    yield put({ type: DATA_APPEND, payload: payload.results });
  } catch (e) {
    yield put({ type: API_ERRORED, payload: e });
  }
}

function* workerMergeData() {
  yield put({ type: DATA_MERGED });
}

function getData(natFilter) {
  return fetch(`https://randomuser.me/api/?results=${BATCH_SIZE}&nat=${natFilter}`).then(response =>
    response.json()
  );
}
