import React, { Component } from 'react';
import { Navbar, Nav, Form, FormControl } from 'react-bootstrap';
import { connect } from 'react-redux';
import { setNameFilter } from '../actions/index';
import { LinkContainer } from 'react-router-bootstrap';

class Appheader extends Component {
  // Arrow fx for `this` binding
  onNameFilterInput = event => {
    this.props.setNameFilter(event.target.value);
  };

  render() {
    return (
      <Navbar bg="light" expand="lg" sticky="top">
        <Navbar.Brand>Address book</Navbar.Brand>
        <Navbar.Toggle aria-controls="basic-navbar-nav" />
        <Navbar.Collapse id="basic-navbar-nav">
          <LinkContainer to="/">
            <Nav.Link>Home</Nav.Link>
          </LinkContainer>
          <LinkContainer to="/settings">
            <Nav.Link>Settings</Nav.Link>
          </LinkContainer>
          <Form inline>
            <FormControl
              type="text"
              placeholder="Search"
              className="mr-sm-2"
              onChange={this.onNameFilterInput}
            />
            <img
              src={`/images/${this.props.countryFilter}.png`}
              width="30"
              height="30"
              className="d-inline-block align-top"
              alt="Country flag"
            />
          </Form>
        </Navbar.Collapse>
      </Navbar>
    );
  }
}

function mapStateToProps(state) {
  return {
    countryFilter: state.countryFilter
  };
}

export default connect(
  mapStateToProps,
  { setNameFilter }
)(Appheader);
