import {
  DATA_LOAD_REQUESTED,
  DATA_APPEND_REQUESTED,
  FILTER_BY_NAME_REQUESTED,
  FILTER_BY_COUNTRY_REQUESTED,
  USER_DETAIL_REQUESTED,
  TRUNCATE_DATA_LOAD_REQUESTED,
  DATA_MERGE_REQUESTED
} from '../constants/action-types';

export function getData() {
  return { type: DATA_LOAD_REQUESTED };
}

export function appendData() {
  return { type: DATA_APPEND_REQUESTED };
}

export function mergeData() {
  return { type: DATA_MERGE_REQUESTED };
}

export function setCountryFilter(countryFilter) {
  return {
    type: FILTER_BY_COUNTRY_REQUESTED,
    countryFilter
  };
}

export function truncateData() {
  return { type: TRUNCATE_DATA_LOAD_REQUESTED };
}

export function setNameFilter(nameFilter) {
  return {
    type: FILTER_BY_NAME_REQUESTED,
    nameFilter
  };
}

export function userDetailToggle(detailUserID) {
  return {
    type: USER_DETAIL_REQUESTED,
    detailUserID
  };
}
