import {
  DATA_LOAD_REQUESTED,
  DATA_LOADED,
  FILTER_BY_NAME_REQUESTED,
  FILTER_BY_COUNTRY_REQUESTED,
  DATA_FILTERED,
  API_ERRORED,
  MAX_USER_LENGTH,
  USER_DETAIL_REQUESTED,
  DETAIL_MODAL_TOGGLE,
  COUNTRY_SWITZERLAND,
  API_SWITZERLAND,
  COUNTRY_FRANCE,
  API_FRANCE,
  COUNTRY_SPAIN,
  API_SPAIN,
  COUNTRY_UK,
  API_UK,
  DATA_TRUNCATED,
  DATA_APPEND,
  DATA_MERGED
} from '../constants/action-types';

const initialState = {
  users: [],
  unfilteredUsers: [],
  nextUsersBatch: [],
  isFetching: false,
  nameFilter: '',
  countryFilter: COUNTRY_SWITZERLAND,
  apiCountryFilter: API_SWITZERLAND,
  endReached: false,
  detailUserID: '',
  currentUser: null
};

const filterUserName = (name, term) =>
  term === '' || name.first.toLowerCase().includes(term) || name.last.toLowerCase().includes(term);

function rootReducer(state = initialState, action) {
  switch (action.type) {
    case DATA_LOADED:
      const unfilteredUsers = state.unfilteredUsers.concat(action.payload);
      const users = unfilteredUsers;
      return {
        ...state,
        unfilteredUsers: unfilteredUsers,
        users: users,
        isFetching: false,
        endReached: users.length >= MAX_USER_LENGTH
      };
    case DATA_MERGED:
      const _unfilteredUsers = state.unfilteredUsers.concat(state.nextUsersBatch);
      const _users = _unfilteredUsers;
      return {
        ...state,
        unfilteredUsers: _unfilteredUsers,
        users: _users,
        nextUsersBatch: [],
        isFetching: false,
        endReached: _users.length >= MAX_USER_LENGTH
      };
    case DATA_APPEND:
      return { ...state, nextUsersBatch: action.payload };
    case DATA_TRUNCATED:
      return { ...state, users: [], unfilteredUsers: [] };
    case DATA_LOAD_REQUESTED:
      return { ...state, isFetching: true };
    case DATA_FILTERED:
      return {
        ...state,
        users: state.unfilteredUsers
          .slice(0, 50)
          .filter(u => filterUserName(u.name, state.nameFilter.toLowerCase()))
      };
    case API_ERRORED:
      return { ...state, isFetching: false };
    case FILTER_BY_NAME_REQUESTED:
      return {
        ...state,
        nameFilter: action.nameFilter
      };
    case FILTER_BY_COUNTRY_REQUESTED:
      let apiCountryFilter = '';
      switch (action.countryFilter) {
        case COUNTRY_SWITZERLAND:
          apiCountryFilter = API_SWITZERLAND;
          break;
        case COUNTRY_FRANCE:
          apiCountryFilter = API_FRANCE;
          break;
        case COUNTRY_SPAIN:
          apiCountryFilter = API_SPAIN;
          break;
        case COUNTRY_UK:
          apiCountryFilter = API_UK;
          break;
        default:
          apiCountryFilter = API_SWITZERLAND;
          break;
      }
      return {
        ...state,
        countryFilter: action.countryFilter,
        apiCountryFilter: apiCountryFilter
      };
    case DETAIL_MODAL_TOGGLE:
      return {
        ...state
      };
    case USER_DETAIL_REQUESTED:
      const currentUser =
        action.detailUserID !== ''
          ? state.users.find(elt => elt.login.uuid === action.detailUserID)
          : null;
      return {
        ...state,
        detailUserID: action.detailUserID,
        currentUser: currentUser
      };
    default:
      return state;
  }
}

export default rootReducer;
